using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their impact on civilization." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control structures, functions, and object-oriented design principles.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming education.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm analysis. Includes sorting, searching, and complexity theory.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Rivera", InstructorBio = "Dr. Rivera specializes in algorithm optimization and competitive programming. Former ACM ICPC world finalist.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing, and transaction management. Includes a semester-long project building a complete database application.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for a decade before joining academia. Her research focuses on distributed database systems." },
            new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Alan Turing Jr.", InstructorBio = "Dr. Turing has been teaching calculus for over 20 years and has authored two best-selling textbooks.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Priya Patel", InstructorBio = "Dr. Patel's research bridges pure mathematics and machine learning applications." },
            new() { Id = 6, DepartmentId = 3, CourseCode = "ENG 110", Title = "Academic Writing", Description = "Develop clear, effective academic writing skills. Focus on argumentation, research methods, citation practices, and revision strategies.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Prof. Emily Dawson", InstructorBio = "Prof. Dawson is a published author and writing coach with expertise in rhetoric and composition studies." },
            new() { Id = 7, DepartmentId = 3, CourseCode = "ENG 220", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present. Explores themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Michael Brooks", InstructorBio = "Dr. Brooks is an award-winning literary critic and specialist in 20th-century American fiction.", IsFeatured = true },
            new() { Id = 8, DepartmentId = 4, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments and data analysis.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an experimental physicist whose research in quantum optics has been featured in Nature and Science." },
            new() { Id = 9, DepartmentId = 4, CourseCode = "PHYS 220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics. Prerequisite: PHYS 101 and MATH 151.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Lisa Zhang", InstructorBio = "Dr. Zhang specializes in photonics and has held research positions at CERN and Fermilab." },
            new() { Id = 10, DepartmentId = 5, CourseCode = "HIST 101", Title = "World Civilizations", Description = "Survey of major world civilizations from ancient Mesopotamia through the modern era. Examines political, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. David Okafor", InstructorBio = "Dr. Okafor is a historian specializing in comparative civilizations and has conducted research on four continents." },
            new() { Id = 11, DepartmentId = 5, CourseCode = "HIST 215", Title = "Modern European History", Description = "Europe from the French Revolution to the present. Topics include industrialization, world wars, decolonization, and European integration.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Anna Schmidt", InstructorBio = "Dr. Schmidt is a specialist in 20th-century European political history and a former Fulbright scholar." },
            new() { Id = 12, DepartmentId = 1, CourseCode = "CS 450", Title = "Artificial Intelligence", Description = "Fundamentals of AI including search algorithms, knowledge representation, machine learning basics, neural networks, and ethical considerations in AI.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming education.", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public string GetDepartmentName(int departmentId) =>
        _departments.FirstOrDefault(d => d.Id == departmentId)?.Name ?? "Unknown";
}

