@page "/"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p>Explore our departments and courses. Find the right classes for your academic journey.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</div>

<section class="featured-section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="badge">@course.CourseCode</span>
                <h3>@course.Title</h3>
                <p>@course.Credits credits &middot; @CatalogService.GetDepartmentName(course.DepartmentId)</p>
                <a href="/courses/@course.Id">View Details</a>
            </div>
        }
    </div>
</section>

<section class="departments-section">
    <h2>Departments</h2>
    <div class="dept-grid">
        @foreach (var dept in departments)
        {
            <div class="dept-card">
                <h3>@dept.Name</h3>
                <p>@dept.Description</p>
                <a href="/courses?departmentId=@dept.Id">View Courses</a>
            </div>
        }
    </div>
</section>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = new();
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="filter-form">
    <input type="text" name="search" value="@Search" placeholder="Search courses..." />
    <select name="departmentId">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-primary">Search</button>
</form>

@if (courses.Any())
{
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-list-item">
                <div class="course-list-header">
                    <span class="badge">@course.CourseCode</span>
                    <h3><a href="/courses/@course.Id">@course.Title</a></h3>
                </div>
                <p>@CatalogService.GetDepartmentName(course.DepartmentId) &middot; @course.Credits credits &middot; @course.Schedule</p>
            </div>
        }
    </div>
}
else
{
    <p class="no-results">No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = new();
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses">Back to Course List</a>
}
else
{
    <PageTitle>@course.Title - University Course Catalog</PageTitle>

    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo;
        <a href="/courses">Courses</a> &rsaquo;
        <a href="/courses?departmentId=@course.DepartmentId">@CatalogService.GetDepartmentName(course.DepartmentId)</a> &rsaquo;
        <span>@course.CourseCode</span>
    </nav>

    <article class="course-detail">
        <header>
            <span class="badge">@course.CourseCode</span>
            <h1>@course.Title</h1>
        </header>

        <div class="detail-grid">
            <section class="detail-main">
                <h2>Description</h2>
                <p>@course.Description</p>

                <h2>Instructor</h2>
                <h3>@course.InstructorName</h3>
                <p>@course.InstructorBio</p>
            </section>

            <aside class="detail-sidebar">
                <dl>
                    <dt>Credits</dt>
                    <dd>@course.Credits</dd>
                    <dt>Schedule</dt>
                    <dd>@course.Schedule</dd>
                    <dt>Department</dt>
                    <dd>@CatalogService.GetDepartmentName(course.DepartmentId)</dd>
                </dl>
                <a href="/enroll?courseId=@course.Id" class="btn-primary">Request Enrollment</a>
            </aside>
        </div>
    </article>
}

@code {
    [Parameter] public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>Request Submitted</h2>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received. You will be notified by email once it is processed.</p>
        <a href="/courses">Browse More Courses</a>
    </div>
}
else
{
    <form method="post" class="enroll-form" @formname="enrollment">
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode - @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn-primary">Submit Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = "";

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;

        // Check if form was posted
        if (!string.IsNullOrEmpty(Model.StudentName) && !string.IsNullOrEmpty(Model.StudentId) && Model.CourseId > 0)
        {
            selectedCourseTitle = courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title ?? "Unknown Course";
            submitted = true;
        }
    }
}

