protected override void OnInitialized()
{
    courses = CatalogService.GetCourses();
    Model ??= new();

    if (CourseId.HasValue && Model.CourseId == 0)
        Model.CourseId = CourseId.Value;

    // Check if form was posted
    if (!string.IsNullOrEmpty(Model.StudentName) && !string.IsNullOrEmpty(Model.StudentId) && Model.CourseId > 0)
    {
        selectedCourseTitle = courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title ?? "Unknown Course";
        submitted = true;
    }
}

