 <PageTitle>Enrollment Request - University Course Catalog</PageTitle>

 <h1>Enrollment Request</h1>

 @if (submitted)
 {
     <div class="success-message">
         <h2>Request Submitted</h2>
         <p>Thank you, <strong>@Model!.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received. You will be notified by email once it is processed.</p>
         <a href="/courses">Browse More Courses</a>
     </div>
 }
 else
 {
     <form method="post" class="enroll-form" @formname="enrollment">
